SELECT ?skyscraper ?skyscraperLabel ?commissioner ?commissionerLabel ?completionYear WHERE {
  ?skyscraper wdt:P31 wd:Q41422 .
  ?skyscraper wdt:P1321 ?height .
  ?skyscraper wdt:P4664 ?commissioner .
  ?skyscraper wdt:P193 ?completionYear .
  FILTER (datatype(?height) = xsd:float) .
  OPTIONAL { ?skyscraper rdfs:label ?skyscraperLabel . FILTER (LANG(?skyscraperLabel) = "en") }
  OPTIONAL { ?commissioner rdfs:label ?commissionerLabel . FILTER (LANG(?commissionerLabel) = "en") }
} ORDER BY DESC(?height) LIMIT 10

